// Merge hospitals and clinics into a single facility list
const allItems = $input.all();
const facilityList = [];

for (const item of allItems) {
  const results = item.json.results || [];
  for (const place of results) {
    facilityList.push({
      placeId: place.place_id,
      name: place.name,
      address: place.vicinity,
      latitude: place.geometry?.location?.lat,
      longitude: place.geometry?.location?.lng,
      rating: place.rating || null,
      openNow: place.opening_hours?.open_now ?? true,
      types: place.types || []
    });
  }
}

// Deduplicate by placeId
const seen = new Set();
const unique = facilityList.filter(f => {
  if (seen.has(f.placeId)) return false;
  seen.add(f.placeId);
  return true;
});

return unique.map(f => ({ json: f }));

// Merge capacity data with facility info
// Falls back to safe defaults if capacity API is unavailable
const facility = $input.item.json;
const capacity = facility.error ? {} : facility;

return {
  json: {
    ...facility,
    edStatus: capacity.ed_status || 'unknown',
    availableBeds: capacity.available_beds ?? -1,
    waitTimeMinutes: capacity.wait_time_minutes ?? 999,
    capacityDataAvailable: !facility.error
  }
};

// Select the top-ranked facility
// Sort by compositeScore descending, pick #1
const items = $input.all().map(i => i.json);

items.sort((a, b) => (b.compositeScore || 0) - (a.compositeScore || 0));

const best = items[0];
const alternatives = items.slice(1, 3); // keep 2 backups

if (!best) {
  return [{ json: { error: 'No facilities found in range', requestId: items[0]?.requestId } }];
}

return [{
  json: {
    ...best,
    alternativeFacilities: alternatives.map(f => ({
      name: f.name,
      address: f.address,
      travelMinutes: f.travelMinutes,
      waitTimeMinutes: f.waitTimeMinutes,
      compositeScore: f.compositeScore
    }))
  }
}];

