// Format final routing output for notification and logging
const item = $input.item.json;

const routingMessage = item.output || item.response || item.text ||
  `Head to ${item.name} (${item.address}). Estimated travel: ${item.travelMinutes} min.`;

return {
  json: {
    ...item,
    routingMessage,
    smsBody: `🚨 EMERGENCY ROUTING\n${routingMessage}\n\nDirections: https://maps.google.com/?q=${item.latitude},${item.longitude}`,
    logDate: new Date().toISOString().split('T')[0],
    logTimestamp: new Date().toISOString()
  }
};

// Error handler: no valid location coordinates provided
const item = $input.item.json;
console.error(`[EmergencyFinder] Invalid location for requestId=${item.requestId}`);
return {
  json: {
    ...item,
    error: 'Invalid or missing GPS coordinates. Please provide valid latitude and longitude.',
    errorCode: 'INVALID_LOCATION',
    success: false
  }
};
